// Todo junto, con fluidez:
const maquinas = [{id:1,activa:false},{id:2,activa:false}];

function activar(maquina, callback) {
  maquina.activa = true;
  callback(maquina);
}

maquinas.forEach(function(m) {
  activar(m, function(result) {
    console.log('Máquina ' + result.id + ' activa');
  });
});

